export type EventType = 'goal' | 'own-goal' | 'penalty';

export interface GoalEvent {
  player:           string;
  team:             string;
  minute:           number;
  minuteStoppage?:  number; // e.g. 5 for "45+5'"
  type:             EventType;
}

export interface CardEvent {
  player:  string;
  team:    string;
  minute?: number;
  reason?: string;
}

// A substitution: who came ON, who went OFF, and when. From api-football's
// `subst` events (player = on, assist = off). Optional so older baked entries
// (generated before subs were captured) stay valid.
export interface SubEvent {
  playerIn:  string;
  playerOut: string;
  team:      string;
  minute?:   number;
}

export interface MatchEvents {
  fixtureId:   string; // matches WCFixture.id
  home:        string;
  away:        string;
  date:        string; // YYYY-MM-DD
  goals:       GoalEvent[];
  yellowCards: CardEvent[];
  redCards:    CardEvent[];
  subs?:       SubEvent[];
}

